Parfait, on va se concentrer exclusivement sur des fonctions qui exploitent SuperLoop à partir d’une liste d’objets déjà chargés (comme modules dans ton exemple). Le but ici est de faciliter des manipulations chaînées, expressives et puissantes, sans gérer la récupération initiale.

✅ Fonctions SuperLoop orientées manipulation d’objets (dictionnaire de type modules)
⚙️ Principe : chaque fonction reçoit une liste objects et retourne un SuperLoop pour continuer le chaînage, ou un collect() ou first() selon les cas.

🔁 Fonctions SuperLoop chainables
pythonCopierModifierfrom app.utils.superloop import SuperLoop

# 🔎 Filtrer uniquement les objets qui ont une valeur dans un champ donné
def filter_has_key(objects, key):
    return SuperLoop(objects).filter(lambda o: key in o and o[key])

# 🔍 Filtrer selon une valeur exacte
def filter_by(objects, key, value):
    return SuperLoop(objects).filter(lambda o: o.get(key) == value)

# 🔍 Filtrer selon une condition personnalisée
def filter_custom(objects, func):
    return SuperLoop(objects).filter(func)

# 🔁 Appliquer une transformation sur un champ donné
def map_key(objects, key):
    return SuperLoop(objects).map(lambda o: o.get(key))

# 🧠 Appliquer une transformation custom
def map_custom(objects, func):
    return SuperLoop(objects).map(func)

# 🖨️ Afficher une clé pour tous les objets
def print_key(objects, key):
    return SuperLoop(objects).print(key)

# 📦 Collecter les objets sous forme de liste finale
def collect(objects):
    return SuperLoop(objects).collect()

# 🎯 Récupérer le premier objet
def first(objects):
    return SuperLoop(objects).first()

# 🔢 Compter le nombre d’objets
def count(objects):
    return SuperLoop(objects).count()

# 🔗 Extraire les objets liés par une relation donnée (enrichis)
def filter_has_relation(objects, relation_name):
    return SuperLoop(objects).filter(
        lambda o: o.get("relations", {}).get("as_source", {}).get(relation_name)
    )

# 🔎 Récupérer les noms (ou n’importe quelle clé) des objets filtrés
def get_names(objects):
    return SuperLoop(objects).map(lambda o: o.get("name")).collect()

# 📌 Trouver un objet dont l’ident ou le nom contient un mot-clé
def search_by_keyword(objects, keyword):
    return SuperLoop(objects).filter(
        lambda o: keyword.lower() in str(o.get("name", "")).lower()
        or keyword.lower() in str(o.get("ident", "")).lower()
    )


🧪 Exemple d’utilisation fluide
pythonCopierModifierfrom app.helpers.object_loop_utils import *

def run_test(modules):
    print("\n🧠 Modules avec datas :")
    filter_has_key(modules, "datas")\
        .each(lambda m: print(m["name"], "→", m["datas"]))

    print("\n🔗 Modules liés à une relation 'depends_on' :")
    filter_has_relation(modules, "depends_on")\
        .print("name")

    print("\n🔎 Modules contenant 'user' dans leur identifiant :")
    search_by_keyword(modules, "user")\
        .print("ident")

    print("\n📦 Liste des noms :")
    print(get_names(modules))

    print("\n🎯 Premier module avec datas :")
    print(first(filter_has_key(modules, "datas").collect()))

    print("\n🔢 Nombre total de modules :", count(modules))

    return "🧪 Test terminé."


