Parfait ! Voici une version intégrée à la classe Object (ou plutôt comme méthodes statiques de type utilitaire sur des dictionnaires d’objets, comme modules), avec pour chaque méthode :


une description rapide,


une signature adaptée à une liste d’objets (déjà enrichis),


un exemple d'utilisation commenté juste en dessous.



✅ Méthodes SuperLoop intégrées à Object (niveau dictionnaire)
pythonCopierModifierfrom app.utils.superloop import SuperLoop

class Object:

    @staticmethod
    def filter_has_key(objects, key):
        """
        Filtre les objets qui possèdent une clé non vide.
        """
        # Exemple :
        # Object.filter_has_key(modules, "datas").print("name")
        return SuperLoop(objects).filter(lambda o: key in o and o[key])

    @staticmethod
    def filter_by(objects, key, value):
        """
        Filtre les objets où une clé spécifique correspond à une valeur donnée.
        """
        # Exemple :
        # Object.filter_by(modules, "status", "active").print("name")
        return SuperLoop(objects).filter(lambda o: o.get(key) == value)

    @staticmethod
    def filter_custom(objects, func):
        """
        Applique un filtre personnalisé via une fonction.
        """
        # Exemple :
        # Object.filter_custom(modules, lambda m: m.get("name", "").startswith("auth"))
        return SuperLoop(objects).filter(func)

    @staticmethod
    def map_key(objects, key):
        """
        Retourne une SuperLoop contenant uniquement les valeurs d’une clé.
        """
        # Exemple :
        # Object.map_key(modules, "name").collect()
        return SuperLoop(objects).map(lambda o: o.get(key))

    @staticmethod
    def map_custom(objects, func):
        """
        Applique une fonction personnalisée à chaque objet.
        """
        # Exemple :
        # Object.map_custom(modules, lambda m: {"id": m["id"], "n": m["name"]}).collect()
        return SuperLoop(objects).map(func)

    @staticmethod
    def print_key(objects, key):
        """
        Affiche la valeur d’une clé spécifique pour chaque objet.
        """
        # Exemple :
        # Object.print_key(modules, "ident")
        return SuperLoop(objects).print(key)

    @staticmethod
    def collect(objects):
        """
        Retourne la liste finale des objets.
        """
        # Exemple :
        # Object.collect(modules)
        return SuperLoop(objects).collect()

    @staticmethod
    def first(objects):
        """
        Retourne le premier objet.
        """
        # Exemple :
        # Object.first(modules)
        return SuperLoop(objects).first()

    @staticmethod
    def count(objects):
        """
        Retourne le nombre total d’objets.
        """
        # Exemple :
        # Object.count(modules)
        return SuperLoop(objects).count()

    @staticmethod
    def filter_has_relation(objects, relation_name):
        """
        Filtre les objets ayant une relation spécifique en tant que source.
        """
        # Exemple :
        # Object.filter_has_relation(modules, "depends_on").print("name")
        return SuperLoop(objects).filter(
            lambda o: o.get("relations", {}).get("as_source", {}).get(relation_name)
        )

    @staticmethod
    def get_names(objects):
        """
        Retourne la liste des noms d’objets.
        """
        # Exemple :
        # Object.get_names(modules)
        return SuperLoop(objects).map(lambda o: o.get("name")).collect()

    @staticmethod
    def search_by_keyword(objects, keyword):
        """
        Recherche les objets dont le nom ou l’ident contient un mot-clé.
        """
        # Exemple :
        # Object.search_by_keyword(modules, "user").print("name")
        return SuperLoop(objects).filter(
            lambda o: keyword.lower() in str(o.get("name", "")).lower()
            or keyword.lower() in str(o.get("ident", "")).lower()
        )


